    TRUE ~ "retained"
  )) |>
  dplyr::filter(exclusion_reason != "retained")

run_summary <- tibble::tibble(
  corpus_tag = CORPUS_TAG,
  dic_tag = DIC_TAG,
  target_outcomes = paste(TARGET_OUTCOMES, collapse = ";"),
  allowed_A_terms = length(allowed_A),
  allowed_B_terms = length(allowed_B),
  measurement_terms_excluded = length(measurement_terms),
  treatment_context_terms_excluded = length(treatment_context_terms(dic)),
  infection_context_terms_excluded = length(infection_context_terms(dic)),
  candidate_pm_triads_current_policy = nrow(triads_current),
  displayed_triads = nrow(triads_display),
  progression_displayed_triads = sum(triads_display$C == "progression"),
  mortality_displayed_triads = sum(triads_display$C == "mortality"),
  bridge_summary_terms_displayed = length(unique(bridge_C_display$B)),
  min_AB_n11 = MIN_AB_N11,
  min_BC_n11 = MIN_BC_N11,
  max_triads_per_outcome = MAX_TRIADS_PER_OUTCOME,
  interpretation = "Figure 4 uses current primary disease-state ABC bridges for progression and mortality; treatment, infection and measurement nodes are excluded from bridge claims."
)

write_csv2(triads_current, table_triads_all)
write_csv2(triads_display, table_triads_display)
