# Robust manual layout. Avoid grid.draw(..., vp=...), which fails on some grid versions.
draw_in_viewport <- function(plot_obj, layout.pos.row, layout.pos.col) {
  grid::pushViewport(grid::viewport(layout.pos.row = layout.pos.row, layout.pos.col = layout.pos.col))
  grid::grid.draw(ggplot2::ggplotGrob(plot_obj))
  grid::popViewport()
}

make_combined <- function() {
  grid::grid.newpage()
  grid::pushViewport(grid::viewport(layout = grid::grid.layout(
    nrow = 2, ncol = 2,
    heights = grid::unit(c(0.50, 0.50), "npc"),
    widths = grid::unit(c(0.50, 0.50), "npc")
  )))
  draw_in_viewport(pA, 1, 1)
  draw_in_viewport(pB, 1, 2)
  draw_in_viewport(pC, 2, 1:2)
  grid::popViewport()
}

